// XXX: This file embeds logo.png as a base64 data URI so the PDF renderer has
// no filesystem dependency at runtime. To regenerate after the logo changes,
// run from the repo root, which I most certainly will forget in the future:
//
//   base64 -w 0 frontend/assets/images/logo.png \
//     | xargs -I{} echo "export const LOGO_DATA_URI = 'data:image/png;base64,{}'" \
//     > api/src/reports/logo.ts
export const LOGO_DATA_URI = 'data:image/png;base64,'
